  "verses": [
    {
      "n": 1,
      "column": "left",
      "text": "Augi/ tas KUNGS\nDarra to Semmi tuk-\nSchu/ unn darra to poh-\nstu/ unn maita winnas Gihmi/\nunn iſkaifa winnas Eedſihwo-\ntajus.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Un ka teem Laudim/ tapott\nflahfees tam Preesteram/ ka tam\nKalpam/ tapatt winna Kun-\ngam/ ka tai Kalponet/ tapatt\nwinnas Gaspaschai/ ka tam Pir-\nzejam/ tapatt tam Bahrdeve-\njam/ ka tam Aisdewejam/ tapatt\ntam Aisnehmejam/ ka tam Pa-\ngadu-Dsinnejam/ tapatt tam/\nno ka winſch Pagaidus plehſch.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Pohſtibt taps ta Semme\npoſſita/ unn ar Laupijuna ap-\nlaupita/ jo tas KUNGS irr\nſcho Wahrdü runnajs.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Ta Semme behdajahs\nunn nonibkſt/ tas Semmes Wir-\nfus tohp wahjſch unn winſch no-\nnibkſt/ tee Augſtakee, no teem\nLaudim tahs Semmes nogurſt.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Jo ta Semme irr ſagah-\nnita faun Eedſihwotaju deht/ jo\ntee vahtkabvj tahs Baantlibas/\nunn pahtgroſſa to Likkami/ unn\niſachzina to muhſchigu Detribu.\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Tadeht no-eht tee Lahsti\nSenmi/ jo kas eekſch tahs d\nwo trr apwainojſchees/tapehz n\nfalst tee Eedſihwotaji tahsSe-\nmes/ unn ne atlifs dauds Zitwe-\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Tag Wihrs behdajahs\ntas Wiyna-Kohks nonthkſt/ wi-\nkam preezigga Sirde bija nopu-\nſchahs.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Tag Preeks to Bung-\nnokluſs/ ta Skanna to Eihafm-\ngo mittejahs/ tas Preeks tah\nKohkleß duſs.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Wihrs ne tohp wat-\ndſerts ar Dſeesmahm/ ſtip-\nDſehreens buhs teem ruhſts ka-\nto dſers.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Tas tukſchajs Piſsfah-\nirr nolauihts/ wiſſi Namn-\nſtahw aiſtlehgti/ ka neiveen-\nwarr nahkt eekſcha.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Schehloſchana irr te-\nWiyna deht us Getahm/ jan-\nWakkarz irr ar wiſſu Preeku/ ta-\nEihafmiba tahs Semmes irr-\ngahjuſt.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Pohſtischana irr tai Piſ-\njahta atliffuſt/ unn ar Brakſch-\nkeſchanu irr tahs Wahrtis fa-\nlaustas.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Jo eekſch tahs Semmes-\nteem Laudim tapatt flahfees/\nka weenam nokrattitam Etjes-\nRohſam/ itt ka ohtrā Laſſicha-\nna/ kad ta Wiyna Nojemſcha-\nna jaw pa Gallam irraid.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Tee pozelš faun Balſti/\ntee preeziggi dſeedahs pahr ta\nKUNGA Gotdibu/ tee no Juhi-\ntas Puſſes gawilehs.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
